#!/usr/bin/env bash
# ============================================================================
# Post-Edit Type Checker — v{{VERSION}}
# Event: PostToolUse | Matcher: Edit,Write
# Generated by {{PROJECT_NAME}} harness-marketplace plugin
# Reads JSON from stdin (Claude Code v2 hook format)
# Non-blocking: always exits 0 (typecheck output goes to stderr)
# ============================================================================
set -uo pipefail

# shellcheck disable=SC1091
source "$(dirname "$0")/_parse.sh"

# ═══ GENERATED RULES (overwritten on upgrade) ═══

FILE_PATH="${TOOL_FILE_PATH:-}"

if [[ -z "$FILE_PATH" ]]; then
  exit 0
fi

# Normalize path separators
FILE_PATH="${FILE_PATH//\\//}"

# Only typecheck TypeScript files
case "$FILE_PATH" in
  *.ts|*.tsx)
    ;;
  *)
    exit 0
    ;;
esac

# Check if file exists
if [[ ! -f "$FILE_PATH" ]]; then
  exit 0
fi

TYPECHECK_CMD="{{TYPECHECK_COMMAND}}"

if [[ -z "$TYPECHECK_CMD" ]]; then
  exit 0
fi

echo "[TYPECHECK] Running type checker after editing $(basename "$FILE_PATH")..." >&2

TYPECHECK_OUTPUT=""
TYPECHECK_OUTPUT=$(eval "$TYPECHECK_CMD" 2>&1) || true
TYPECHECK_EXIT=$?

if [[ "$TYPECHECK_EXIT" -ne 0 ]]; then
  echo "[TYPECHECK] Type errors detected:" >&2
  echo "$TYPECHECK_OUTPUT" >&2
  echo "" >&2
  echo "[TYPECHECK] Fix type errors before proceeding." >&2
elif [[ -n "$TYPECHECK_OUTPUT" ]]; then
  # Some type checkers output info even on success
  echo "$TYPECHECK_OUTPUT" >&2
fi

# ═══ CUSTOM RULES BELOW (preserved on upgrade) ═══

# Add your own post-edit typecheck rules here.
# They will be preserved when the plugin is upgraded.
#
# Example: Run additional type checking for specific modules
#   case "$FILE_PATH" in
#     */api/types/*)
#       echo "[TYPECHECK] Running strict type check for API types..." >&2
#       npx tsc --strict --noEmit "$FILE_PATH" 2>&1 >&2 || true
#       ;;
#   esac

# Non-blocking: always exit 0
exit 0
